( function( $ ) {
	"use strict";
	var network_posts_widget = function() {
		/*
		jQuery( '.netsposts-block-wrapper' ).each( function(){
			$('.netsposts-block-wrapper .elementor-posts-masonry').masonry({				
				itemSelector: '.netsposts-content',			  
			});
		});
		*/
		$( '.elementor-widget-network_posts_widget').each( function() {
			var settings = $(this).data('settings');
			var currentDeviceMode = elementorFrontend.getCurrentDeviceMode(), colsCount;
			
			switch (currentDeviceMode) {
				case 'mobile':
					colsCount = settings.columns_mobile;
				break;

				case 'tablet':
					colsCount = settings.columns_tablet;
				break;

				default:
					colsCount = settings.columns;
			}
			
			
			var verticalSpaceBetween = settings.row_gap.size;
			if ( '' === verticalSpaceBetween) {
				verticalSpaceBetween = settings.item_gap.size;
			}
			
			var masonry = new elementorFrontend.modules.Masonry( {
				container: $('.netsposts-block-wrapper .elementor-posts-masonry'), //section css class of container (blog post widget)
				items: $('.netsposts-content'), //css class of each single item
				columnsCount: colsCount, //column count, needs adaption to different breakpoints
				 verticalSpaceBetween: verticalSpaceBetween || 0
			} );
			masonry.run();
		});
	}
	$( window ).on(
		'elementor/frontend/init',
		() => {
			elementorFrontend.hooks.addAction( 'frontend/element_ready/network_posts_widget.default', network_posts_widget );
		}
	);

})( jQuery );
